UPDATE tour SET description = 'Straddle two continents on an extraordinary journey through Istanbul, the only city in the world spanning Europe and Asia. Explore the magnificent Hagia Sophia, the dazzling Blue Mosque, and the labyrinthine Grand Bazaar. Cross the Bosphorus by ferry, savor street-side baklava, and watch the sun set over minarets. Istanbul''s layered history and cosmopolitan energy make it utterly unlike anywhere else on Earth.' WHERE id = '019ee5e8-21b2-72de-b4f4-6bb51400c2e3';
